function Search({
  onSearch,
  onReset,
  onSearchValueChange,
  query,
  isSearching,
  activeQuery
}) {
  const handleSubmit = async (event) => {
    event.preventDefault();
    await onSearch(query);
  };

  const handleReset = async () => {
    await onReset();
  };

  return (
    <section className="panel">
      <h2>Search Files</h2>
      <p className="panel-copy">
        Search by filename to instantly narrow the workspace. Clear the query to
        return to the full inventory.
      </p>

      <form onSubmit={handleSubmit} className="stack">
        <div className="search-input-shell">
          <input
            type="text"
            className="text-input"
            placeholder="Search by filename, extension, or keyword"
            value={query}
            onChange={(event) => onSearchValueChange(event.target.value)}
          />
          <button type="submit" className="primary-button search-button">
            {isSearching ? "Searching..." : "Search"}
          </button>
        </div>

        <div className="button-row">
          <button type="button" className="secondary-button" onClick={handleReset}>
            Show All Files
          </button>
          {activeQuery.trim() && <span className="search-chip">Active filter: {activeQuery}</span>}
        </div>
      </form>
    </section>
  );
}

export default Search;
